// src/components/ImportExportData.js
import React, { useState } from 'react';

export default function ImportExportData({ products, onImport }) {
  const [importedData, setImportedData] = useState(null);
  const [showPreview, setShowPreview] = useState(false);

  // Export au format JSON
  const handleExportFile = () => {
    const dataStr = JSON.stringify(products, null, 2);
    const dataBlob = new Blob([dataStr], { type: 'application/json' });
    const url = URL.createObjectURL(dataBlob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `produits-saveurs-export-${new Date().getTime()}.json`;
    link.click();
    URL.revokeObjectURL(url);
  };

  // Copier les données au presse-papiers
  const handleCopyToClipboard = async () => {
    try {
      const dataStr = JSON.stringify(products, null, 2);
      await navigator.clipboard.writeText(dataStr);
      alert('Données copiées au presse-papiers !');
    } catch (error) {
      console.error('Erreur lors de la copie:', error);
      alert('Erreur lors de la copie');
    }
  };

  // Importer depuis un fichier
  const handleImportFile = (event) => {
    const file = event.target.files[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (e) => {
      try {
        const content = e.target.result;
        let data;

        // Parser le JSON
        try {
          data = JSON.parse(content);
        } catch (jsonError) {
          alert('Erreur : le fichier n\'est pas un JSON valide');
          console.error('Erreur JSON:', jsonError);
          return;
        }

        // Vérifier que c'est un tableau
        if (!Array.isArray(data)) {
          alert('Erreur : le fichier doit contenir un tableau de produits');
          return;
        }

        // Vérifier et formater les produits
        const formattedData = data.map((item, index) => {
          return {
            id: item.id || `import-${index}`,
            name: item.name || '',
            manufacturer: item.manufacturer || '',
            flavors: Array.isArray(item.flavors) 
              ? item.flavors 
              : (item.flavors ? [item.flavors] : []),
            image: item.image || item.image_url || '/images/placeholder.jpg'
          };
        });

        // Vérifier qu'on a au moins des produits valides
        const validProducts = formattedData.filter(p => p.name && p.manufacturer);
        
        if (validProducts.length === 0) {
          alert('Erreur : aucun produit valide trouvé (besoin de "name" et "manufacturer")');
          return;
        }

        setImportedData(formattedData);
        setShowPreview(true);
      } catch (error) {
        console.error('Erreur lors de l\'import:', error);
        alert('Erreur lors de la lecture du fichier');
      }
    };

    reader.readAsText(file);
    event.target.value = '';
  };

  // Importer depuis le presse-papiers
  const handleImportFromClipboard = async () => {
    try {
      const text = await navigator.clipboard.readText();
      
      let data;
      try {
        data = JSON.parse(text);
      } catch (jsonError) {
        alert('Erreur : le contenu du presse-papiers n\'est pas un JSON valide');
        return;
      }

      if (!Array.isArray(data)) {
        alert('Erreur : le contenu doit être un tableau de produits');
        return;
      }

      const formattedData = data.map((item, index) => {
        return {
          id: item.id || `import-${index}`,
          name: item.name || '',
          manufacturer: item.manufacturer || '',
          flavors: Array.isArray(item.flavors) 
            ? item.flavors 
            : (item.flavors ? [item.flavors] : []),
          image: item.image || item.image_url || '/images/placeholder.jpg'
        };
      });

      const validProducts = formattedData.filter(p => p.name && p.manufacturer);
      
      if (validProducts.length === 0) {
        alert('Erreur : aucun produit valide trouvé');
        return;
      }

      setImportedData(formattedData);
      setShowPreview(true);
    } catch (error) {
      alert('Erreur lors de la lecture du presse-papiers');
    }
  };

  // Confirmer l'importation
  const handleConfirmImport = async () => {
    if (!importedData || importedData.length === 0) return;

    try {
      const validProducts = importedData.filter(p => p.name && p.manufacturer);
      
      alert(`Importation de ${validProducts.length} produits...`);
      
      if (onImport) {
        onImport(validProducts);
      }
      
      setShowPreview(false);
      setImportedData(null);
    } catch (error) {
      console.error('Erreur lors de l\'importation:', error);
      alert('Erreur lors de l\'importation');
    }
  };

  // Annuler l'importation
  const handleCancelImport = () => {
    setShowPreview(false);
    setImportedData(null);
  };

  return (
    <div className="import-export-panel">
      <h3>Importation/Exportation des données</h3>

      <div className="button-group">
        <button 
          className="export-button"
          onClick={handleCopyToClipboard}
          type="button"
        >
          Copier les données
        </button>

        <button 
          className="export-button"
          onClick={handleExportFile}
          type="button"
        >
          Exporter en fichier
        </button>

        <button 
          className="import-button"
          onClick={handleImportFromClipboard}
          type="button"
        >
          Importer des données
        </button>

        <label className="import-button" style={{ cursor: 'pointer', display: 'inline-block' }}>
          Importer depuis fichier
          <input 
            type="file" 
            accept=".json"
            onChange={handleImportFile}
            style={{ display: 'none' }}
          />
        </label>
      </div>

      {showPreview && importedData && (
        <div className="import-preview">
          <h4>Aperçu de l'import ({importedData.length} produits)</h4>
          <div className="preview-list">
            {importedData.slice(0, 5).map((product, index) => (
              <div key={index} className="preview-item">
                <strong>{product.name}</strong> - {product.manufacturer}
                <br />
                <small>{product.flavors.join(', ')}</small>
              </div>
            ))}
            {importedData.length > 5 && (
              <div className="preview-item">
                ... et {importedData.length - 5} produits de plus
              </div>
            )}
          </div>

          <div className="button-group">
            <button 
              className="confirm-button"
              onClick={handleConfirmImport}
              type="button"
            >
              Confirmer l'importation
            </button>
            <button 
              className="cancel-button"
              onClick={handleCancelImport}
              type="button"
            >
              Annuler
            </button>
          </div>
        </div>
      )}
    </div>
  );
}