// src/components/ProductCard.js
import React from 'react';
import { highlightMatch } from '../utils/stringUtils';

const ProductCard = ({ product, onDelete, onEdit, searchTerm }) => {
  // Fonction pour garantir l'affichage correct des caract�res accentu�s
  const ensureCorrectEncoding = (text) => {
    if (!text) return '';
    
    // Si le texte contient des caract�res bizarres, essayer de les corriger
    if (text.includes('?') || text.includes('?')) {
      try {
        // M�thode 1 : d�coder depuis UTF-8
        return decodeURIComponent(escape(text));
      } catch (e) {
        console.warn('Impossible de d�coder:', text);
        return text;
      }
    }
    
    return text;
  };

  // G�rer les images manquantes avec une image par d�faut
  const handleImageError = (e) => {
    console.log("Erreur de chargement d'image, utilisation de l'image par d�faut");
    e.target.src = '/images/placeholder.jpg';
  };

  // G�rer la suppression en appelant la fonction du parent
  const handleDelete = (e) => {
    e.stopPropagation(); // Emp�cher la propagation de l'�v�nement
    onDelete(product.id);
  };

  // G�rer l'�dition en appelant la fonction du parent
  const handleEdit = (e) => {
    e.stopPropagation(); // Emp�cher la propagation de l'�v�nement
    onEdit(product.id);
  };

  // D�termine si le contenu HTML doit �tre utilis� (mise en �vidence)
  const shouldHighlight = searchTerm && searchTerm.length > 1;

  return (
    <div className="product-card">
      <div className="product-image">
        <img 
          src={product.image} 
          alt={ensureCorrectEncoding(product.name)}
          onError={handleImageError}
        />
        <div className="card-actions">
          <button 
            className="edit-button"
            onClick={handleEdit}
            title="Modifier ce produit"
          >
            Edit
          </button>
          <button 
            className="delete-button"
            onClick={handleDelete}
            title="Supprimer ce produit"
          >
            X
          </button>
        </div>
      </div>
      <div className="product-info">
        <h3>
          {shouldHighlight ? (
            <span dangerouslySetInnerHTML={highlightMatch(
              ensureCorrectEncoding(product.name), 
              searchTerm, 
              false, 
              true
            )} />
          ) : (
            ensureCorrectEncoding(product.name)
          )}
        </h3>
        <p className="manufacturer">Fabricant: {ensureCorrectEncoding(product.manufacturer)}</p>
        <div className="flavors">
          <p>Saveurs:</p>
          <div className="flavor-tags">
            {product.flavors.map((flavor, index) => (
              <span key={index} className="flavor-tag">
                {shouldHighlight ? (
                  <span dangerouslySetInnerHTML={highlightMatch(
                    ensureCorrectEncoding(flavor),
                    searchTerm,
                    false,
                    true
                  )} />
                ) : (
                  ensureCorrectEncoding(flavor)
                )}
              </span>
            ))}
          </div>
        </div>
      </div>
    </div>
  );
};

export default ProductCard;