// src/firebase/firestoreService.js
import { 
  collection, 
  getDocs, 
  addDoc, 
  updateDoc, 
  deleteDoc, 
  doc 
} from 'firebase/firestore';
import { db } from './config';

const COLLECTION_NAME = 'products';

export const getProducts = async () => {
  try {
    const querySnapshot = await getDocs(collection(db, COLLECTION_NAME));
    const products = querySnapshot.docs.map(document => ({
      id: document.id,
      ...document.data()
    }));
    return products;
  } catch (error) {
    console.error('Erreur lors de la récupération des produits:', error);
    return [];
  }
};

export const addProduct = async (product) => {
  try {
    const docRef = await addDoc(collection(db, COLLECTION_NAME), product);
    return { id: docRef.id, ...product };
  } catch (error) {
    console.error('Erreur lors de l\'ajout du produit:', error);
    throw error;
  }
};

export const updateProduct = async (productId, productData) => {
  try {
    const productRef = doc(db, COLLECTION_NAME, productId);
    await updateDoc(productRef, productData);
    return { id: productId, ...productData };
  } catch (error) {
    console.error('Erreur lors de la mise à jour du produit:', error);
    throw error;
  }
};

export const deleteProduct = async (productId) => {
  try {
    await deleteDoc(doc(db, COLLECTION_NAME, productId));
  } catch (error) {
    console.error('Erreur lors de la suppression du produit:', error);
    throw error;
  }
};

export const deleteAllProducts = async () => {
  try {
    const querySnapshot = await getDocs(collection(db, COLLECTION_NAME));
    const deletePromises = querySnapshot.docs.map(document => 
      deleteDoc(doc(db, COLLECTION_NAME, document.id))
    );
    await Promise.all(deletePromises);
  } catch (error) {
    console.error('Erreur lors de la suppression de tous les produits:', error);
    throw error;
  }
};

export const migrateFromLocalStorage = async () => {
  try {
    const localData = localStorage.getItem('products');
    if (!localData) {
      console.log('Aucune donnée à migrer');
      return 0;
    }

    const products = JSON.parse(localData);
    
    const addPromises = products.map(product => {
      const { id, ...productData } = product;
      return addDoc(collection(db, COLLECTION_NAME), productData);
    });
    
    await Promise.all(addPromises);
    console.log(`${products.length} produits migrés avec succès`);
    
    return products.length;
  } catch (error) {
    console.error('Erreur lors de la migration:', error);
    throw error;
  }
};